/* 01_setup.sas */
proc sql;
    create table raw_data as
    select 'Apple' as item, 10 as qty, 0.5 as price union all
    select 'Banana', 20, 0.2 union all
    select 'Cherry', 15, 1.0;
quit;

proc sql; select * from raw_data; quit;

/* 02_transform.sas */
data processed_data;
    set raw_data;
    total_value = qty * price;
run;

proc sql; select * from processed_data; quit;

/* 03_summary.sas */
proc sql;
    create table final_summary as
    select 
        count(*) as total_items,
        sum(qty) as total_qty,
        sum(total_value) as grand_total
    from processed_data;
quit;

proc sql; select * from final_summary; quit;

data with_revenue;
    set raw_data;
    revenue = qty * price;
run;

proc print data=with_revenue; run;

proc sql;
    create table raw_data as
    select * from (values
        ('Apple',      10, 0.5),
        ('Banana',     20, 0.2),
        ('Cherry',     15, 1.0),
        ('Date',       30, 0.8),
        ('Elderberry',  5, 2.0),
        ('Fig',        12, 0.9),
        ('Grape',       8, 1.2),
        ('Honeydew',    3, 3.5)
    ) as t(item, qty, price);
quit;
